1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) unchanged as still life", () => {
15	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    expect(nextGeneration(block).sort()).toEqual(block.sort());
17	  });
18	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
19	    const vertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
20	    const horizontal: Cell[] = [[-1, 1], [0, 1], [1, 1]];
21	    expect(nextGeneration(vertical).sort()).toEqual(horizontal.sort());
22	  });
23	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
24	    const input: Cell[] = [[0, 0], [1, 0], [0, 1]];
25	    const expected: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
26	    expect(nextGeneration(input).sort()).toEqual(expected.sort());
27	  });
28	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
29	    // A block (still life) with an extra live cell added at (2,1).
30	    // The cell (1,1) now has 4 live neighbors: (0,0), (1,0), (0,1), (2,1)
31	    // → must die from overpopulation.
32	    const input: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1], [2, 1]];
33	    const result = nextGeneration(input);
34	    const hasCell = (x: number, y: number) =>
35	      result.some(([rx, ry]) => rx === x && ry === y);
36	    expect(hasCell(1, 1)).toBe(false);
37	  });
38	  it("should handle negative coordinates correctly", () => {
39	    // A block at negative coordinates remains a still life.
40	    const block: Cell[] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
41	    expect(nextGeneration(block).sort()).toEqual(block.sort());
42	  });
43	});
